import API from "./api"; // your axios instance

const submitMood = async (moodInput, notesInput) => {
    try {
        const response = await API.post("mood/", {
            mood: moodInput,
            notes: notesInput || ""  // optional
        });
        console.log("Mood logged:", response.data);
    } catch (error) {
        console.error("Error submitting mood:", error);
    }
};
